import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  createAnalyticsHandlers,
  ValidationError,
} from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { AnalyticsResponse, DashboardData, MetricDetail, TopProduct } from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// Seed-data helpers
// ---------------------------------------------------------------------------

/** Create an order with sensible defaults. */
function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'prod-1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'confirmed',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/** Create a user with sensible defaults. */
function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/** Helper to build a RouteRequest. */
function req(
  query: Record<string, string>,
  params: Record<string, string> = {},
): RouteRequest {
  return { params, query };
}

/** Returns a date N days ago from now. */
function daysAgo(n: number): Date {
  return new Date(Date.now() - n * 24 * 60 * 60 * 1000);
}

// ---------------------------------------------------------------------------
// Integration tests — full pipeline: route handler → service → repository
// ---------------------------------------------------------------------------

describe('Analytics Integration Tests', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let handlers: ReturnType<typeof createAnalyticsHandlers>;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    handlers = createAnalyticsHandlers(service);
  });

  // -----------------------------------------------------------------------
  // Seed helper — populates realistic data spanning several time ranges
  // -----------------------------------------------------------------------

  function seedData() {
    // Users created at various times
    userRepo.save(makeUser({ id: 'u1', name: 'Alice', createdAt: daysAgo(5), updatedAt: daysAgo(5) }));
    userRepo.save(makeUser({ id: 'u2', name: 'Bob', createdAt: daysAgo(10), updatedAt: daysAgo(10) }));
    userRepo.save(makeUser({ id: 'u3', name: 'Carol', createdAt: daysAgo(20), updatedAt: daysAgo(20) }));
    userRepo.save(makeUser({ id: 'u4', name: 'Dave', createdAt: daysAgo(40), updatedAt: daysAgo(40) }));

    // Orders spread across time with varying products and amounts
    orderRepo.save(makeOrder({
      id: 'o1',
      userId: 'u1',
      items: [
        { productId: 'p1', name: 'Widget A', quantity: 2, unitPrice: 25 },
        { productId: 'p2', name: 'Widget B', quantity: 1, unitPrice: 50 },
      ],
      total: 100,
      createdAt: daysAgo(2),
      updatedAt: daysAgo(2),
    }));

    orderRepo.save(makeOrder({
      id: 'o2',
      userId: 'u2',
      items: [
        { productId: 'p1', name: 'Widget A', quantity: 3, unitPrice: 25 },
      ],
      total: 75,
      createdAt: daysAgo(5),
      updatedAt: daysAgo(5),
    }));

    orderRepo.save(makeOrder({
      id: 'o3',
      userId: 'u3',
      items: [
        { productId: 'p3', name: 'Widget C', quantity: 1, unitPrice: 200 },
      ],
      total: 200,
      createdAt: daysAgo(15),
      updatedAt: daysAgo(15),
    }));

    orderRepo.save(makeOrder({
      id: 'o4',
      userId: 'u1',
      items: [
        { productId: 'p2', name: 'Widget B', quantity: 2, unitPrice: 50 },
        { productId: 'p3', name: 'Widget C', quantity: 1, unitPrice: 200 },
      ],
      total: 300,
      createdAt: daysAgo(25),
      updatedAt: daysAgo(25),
    }));

    orderRepo.save(makeOrder({
      id: 'o5',
      userId: 'u4',
      items: [
        { productId: 'p1', name: 'Widget A', quantity: 5, unitPrice: 25 },
      ],
      total: 125,
      createdAt: daysAgo(35),
      updatedAt: daysAgo(35),
    }));
  }

  // =========================================================================
  // Dashboard end-to-end
  // =========================================================================

  describe('GET /api/analytics/dashboard — full pipeline', () => {
    it('returns complete dashboard with seeded data', async () => {
      seedData();

      const res = await handlers.getDashboard(req({ timeRange: '30d' }));

      expect(res.status).toBe(200);
      const body = res.body as AnalyticsResponse<DashboardData>;
      expect(body.success).toBe(true);

      // summaries: 4 metric types
      expect(body.data.summaries).toHaveLength(4);
      const metrics = body.data.summaries.map((s) => s.metric);
      expect(metrics).toEqual(['orders', 'revenue', 'users', 'products']);

      // Each summary has the expected shape
      for (const s of body.data.summaries) {
        expect(s).toHaveProperty('currentValue');
        expect(s).toHaveProperty('previousValue');
        expect(s).toHaveProperty('changePercent');
        expect(s).toHaveProperty('trend');
        expect(s).toHaveProperty('label');
        expect(['up', 'down', 'flat']).toContain(s.trend);
      }

      // time series present
      expect(body.data.revenueTimeSeries.metric).toBe('revenue');
      expect(body.data.revenueTimeSeries.points.length).toBeGreaterThan(0);
      expect(body.data.orderTimeSeries.metric).toBe('order_count');
      expect(body.data.orderTimeSeries.points.length).toBeGreaterThan(0);

      // top products present
      expect(body.data.topProducts).toBeInstanceOf(Array);

      // generatedAt is ISO string
      expect(new Date(body.data.generatedAt).toISOString()).toBe(body.data.generatedAt);

      // query echo
      expect(body.query.timeRange).toBe('30d');
    });

    it('reflects actual order counts in summaries for 7d range', async () => {
      seedData();
      // In the last 7 days: o1 (2 days ago), o2 (5 days ago) = 2 orders

      const res = await handlers.getDashboard(req({ timeRange: '7d' }));
      const body = res.body as AnalyticsResponse<DashboardData>;
      const orderSummary = body.data.summaries.find((s) => s.metric === 'orders')!;

      expect(orderSummary.currentValue).toBe(2);
    });

    it('calculates revenue correctly for 7d range', async () => {
      seedData();
      // o1 total=100, o2 total=75 → 175

      const res = await handlers.getDashboard(req({ timeRange: '7d' }));
      const body = res.body as AnalyticsResponse<DashboardData>;
      const revSummary = body.data.summaries.find((s) => s.metric === 'revenue')!;

      expect(revSummary.currentValue).toBe(175);
    });

    it('returns empty data when no records exist', async () => {
      const res = await handlers.getDashboard(req({ timeRange: '30d' }));
      const body = res.body as AnalyticsResponse<DashboardData>;

      expect(body.data.summaries).toHaveLength(4);
      for (const s of body.data.summaries) {
        expect(s.currentValue).toBe(0);
        expect(s.previousValue).toBe(0);
        expect(s.trend).toBe('flat');
      }
      expect(body.data.topProducts).toHaveLength(0);
    });

    it('uses custom date range for dashboard', async () => {
      seedData();
      const start = daysAgo(10).toISOString();
      const end = daysAgo(1).toISOString();

      const res = await handlers.getDashboard(
        req({ timeRange: 'custom', startDate: start, endDate: end }),
      );

      const body = res.body as AnalyticsResponse<DashboardData>;
      expect(body.success).toBe(true);
      // o1 (2d ago) and o2 (5d ago) fall within this range
      const orderSummary = body.data.summaries.find((s) => s.metric === 'orders')!;
      expect(orderSummary.currentValue).toBe(2);
    });

    it('respects granularity in time series buckets', async () => {
      seedData();

      const dayRes = await handlers.getDashboard(req({ timeRange: '7d', granularity: 'day' }));
      const hourRes = await handlers.getDashboard(req({ timeRange: '7d', granularity: 'hour' }));

      const dayBody = dayRes.body as AnalyticsResponse<DashboardData>;
      const hourBody = hourRes.body as AnalyticsResponse<DashboardData>;

      // hourly should have more buckets than daily for the same range
      expect(hourBody.data.revenueTimeSeries.points.length).toBeGreaterThan(
        dayBody.data.revenueTimeSeries.points.length,
      );
    });
  });

  // =========================================================================
  // Metric detail end-to-end
  // =========================================================================

  describe('GET /api/analytics/metrics/:type — full pipeline', () => {
    it('returns correct revenue detail with seeded data', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '30d' }, { type: 'revenue' }),
      );

      expect(res.status).toBe(200);
      const body = res.body as AnalyticsResponse<MetricDetail>;
      expect(body.data.summary.metric).toBe('revenue');
      // o1=100, o2=75, o3=200 in last 30d
      expect(body.data.summary.currentValue).toBe(375);
      expect(body.data.timeSeries.points.length).toBeGreaterThan(0);
      expect(body.data.generatedAt).toBeDefined();
    });

    it('returns correct orders count', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '30d' }, { type: 'orders' }),
      );
      const body = res.body as AnalyticsResponse<MetricDetail>;
      // o1, o2, o3 in last 30 days; o4 is 25 days ago (also in 30d)
      expect(body.data.summary.currentValue).toBe(4);
    });

    it('returns user count for users metric', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '30d' }, { type: 'users' }),
      );
      const body = res.body as AnalyticsResponse<MetricDetail>;
      // u1 (5d), u2 (10d), u3 (20d) in last 30 days
      expect(body.data.summary.currentValue).toBe(3);
    });

    it('returns products sold count', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '7d' }, { type: 'products' }),
      );
      const body = res.body as AnalyticsResponse<MetricDetail>;
      // o1: 2+1=3, o2: 3 → total 6 products in 7d
      expect(body.data.summary.currentValue).toBe(6);
    });

    it('computes period-over-period trend correctly', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '7d' }, { type: 'orders' }),
      );
      const body = res.body as AnalyticsResponse<MetricDetail>;

      // 7d: 2 orders (o1, o2). Previous 7d (7-14 days ago): 0 orders
      // current>0, previous=0 → changePercent=100, trend=up
      expect(body.data.summary.trend).toBe('up');
      expect(body.data.summary.changePercent).toBe(100);
    });

    it('time series values sum to total', async () => {
      seedData();

      const res = await handlers.getMetricDetail(
        req({ timeRange: '30d', granularity: 'day' }, { type: 'revenue' }),
      );
      const body = res.body as AnalyticsResponse<MetricDetail>;

      const timeSeriesTotal = body.data.timeSeries.points.reduce((s, p) => s + p.value, 0);
      expect(timeSeriesTotal).toBe(body.data.summary.currentValue);
    });
  });

  // =========================================================================
  // Top products end-to-end
  // =========================================================================

  describe('GET /api/analytics/top-products — full pipeline', () => {
    it('returns products ranked by revenue', async () => {
      seedData();

      const res = await handlers.getTopProducts(req({ timeRange: '30d' }));
      expect(res.status).toBe(200);
      const body = res.body as AnalyticsResponse<TopProduct[]>;

      expect(body.data.length).toBeGreaterThan(0);

      // Verify sorted by revenue descending
      for (let i = 1; i < body.data.length; i++) {
        expect(body.data[i - 1].totalRevenue).toBeGreaterThanOrEqual(body.data[i].totalRevenue);
      }
    });

    it('aggregates products correctly across orders', async () => {
      seedData();

      const res = await handlers.getTopProducts(req({ timeRange: '30d' }));
      const body = res.body as AnalyticsResponse<TopProduct[]>;

      // p1 Widget A: o1 (qty 2 @ $25 = $50), o2 (qty 3 @ $25 = $75) → total qty=5, revenue=$125
      const widgetA = body.data.find((p) => p.productId === 'p1');
      expect(widgetA).toBeDefined();
      expect(widgetA!.totalQuantity).toBe(5);
      expect(widgetA!.totalRevenue).toBe(125);
      expect(widgetA!.orderCount).toBe(2);

      // p2 Widget B: o1 (qty 1 @ $50 = $50), o4 (qty 2 @ $50 = $100) → total qty=3, revenue=$150
      const widgetB = body.data.find((p) => p.productId === 'p2');
      expect(widgetB).toBeDefined();
      expect(widgetB!.totalQuantity).toBe(3);
      expect(widgetB!.totalRevenue).toBe(150);
      expect(widgetB!.orderCount).toBe(2);

      // p3 Widget C: o3 (qty 1 @ $200 = $200), o4 (qty 1 @ $200 = $200) → total qty=2, revenue=$400
      const widgetC = body.data.find((p) => p.productId === 'p3');
      expect(widgetC).toBeDefined();
      expect(widgetC!.totalQuantity).toBe(2);
      expect(widgetC!.totalRevenue).toBe(400);
      expect(widgetC!.orderCount).toBe(2);
    });

    it('respects limit parameter', async () => {
      seedData();

      const res = await handlers.getTopProducts(req({ timeRange: '30d', limit: '2' }));
      const body = res.body as AnalyticsResponse<TopProduct[]>;

      expect(body.data).toHaveLength(2);
      // Top 2 by revenue: p3 ($400), p2 ($150)
      expect(body.data[0].productId).toBe('p3');
      expect(body.data[1].productId).toBe('p2');
    });

    it('returns empty array when no orders in range', async () => {
      seedData();

      // Use a custom range with no orders
      const res = await handlers.getTopProducts(
        req({ timeRange: 'custom', startDate: '2020-01-01', endDate: '2020-01-31' }),
      );
      const body = res.body as AnalyticsResponse<TopProduct[]>;
      expect(body.data).toHaveLength(0);
    });

    it('filters by time range correctly', async () => {
      seedData();

      // 7d should only include o1, o2
      const res = await handlers.getTopProducts(req({ timeRange: '7d' }));
      const body = res.body as AnalyticsResponse<TopProduct[]>;

      // Only p1 and p2 should appear (from o1 and o2)
      const productIds = body.data.map((p) => p.productId).sort();
      expect(productIds).toEqual(['p1', 'p2']);
    });
  });

  // =========================================================================
  // Error scenarios
  // =========================================================================

  describe('Error scenarios', () => {
    it('rejects invalid timeRange', async () => {
      await expect(
        handlers.getDashboard(req({ timeRange: 'invalid' })),
      ).rejects.toThrow(ValidationError);
    });

    it('rejects invalid metric type', async () => {
      await expect(
        handlers.getMetricDetail(req({ timeRange: '7d' }, { type: 'invalid' })),
      ).rejects.toThrow(ValidationError);
    });

    it('rejects custom range without dates', async () => {
      await expect(
        handlers.getDashboard(req({ timeRange: 'custom' })),
      ).rejects.toThrow(ValidationError);
    });

    it('rejects custom range with start >= end', async () => {
      await expect(
        handlers.getDashboard(
          req({
            timeRange: 'custom',
            startDate: '2025-06-01',
            endDate: '2025-01-01',
          }),
        ),
      ).rejects.toThrow(ValidationError);
    });

    it('rejects invalid granularity', async () => {
      await expect(
        handlers.getDashboard(req({ timeRange: '7d', granularity: 'minute' })),
      ).rejects.toThrow(ValidationError);
    });

    it('rejects invalid date format', async () => {
      await expect(
        handlers.getDashboard(
          req({
            timeRange: 'custom',
            startDate: 'not-a-date',
            endDate: '2025-12-31',
          }),
        ),
      ).rejects.toThrow(ValidationError);
    });
  });

  // =========================================================================
  // Cross-endpoint consistency
  // =========================================================================

  describe('Cross-endpoint consistency', () => {
    it('dashboard revenue matches metric detail revenue', async () => {
      seedData();

      const dashRes = await handlers.getDashboard(req({ timeRange: '30d' }));
      const metricRes = await handlers.getMetricDetail(
        req({ timeRange: '30d' }, { type: 'revenue' }),
      );

      const dashBody = dashRes.body as AnalyticsResponse<DashboardData>;
      const metricBody = metricRes.body as AnalyticsResponse<MetricDetail>;

      const dashRevenue = dashBody.data.summaries.find((s) => s.metric === 'revenue')!;
      expect(dashRevenue.currentValue).toBe(metricBody.data.summary.currentValue);
      expect(dashRevenue.previousValue).toBe(metricBody.data.summary.previousValue);
      expect(dashRevenue.changePercent).toBe(metricBody.data.summary.changePercent);
    });

    it('dashboard order count matches metric detail order count', async () => {
      seedData();

      const dashRes = await handlers.getDashboard(req({ timeRange: '7d' }));
      const metricRes = await handlers.getMetricDetail(
        req({ timeRange: '7d' }, { type: 'orders' }),
      );

      const dashBody = dashRes.body as AnalyticsResponse<DashboardData>;
      const metricBody = metricRes.body as AnalyticsResponse<MetricDetail>;

      const dashOrders = dashBody.data.summaries.find((s) => s.metric === 'orders')!;
      expect(dashOrders.currentValue).toBe(metricBody.data.summary.currentValue);
    });

    it('top products revenue sums match revenue summary for same range', async () => {
      seedData();

      const metricRes = await handlers.getMetricDetail(
        req({ timeRange: '30d' }, { type: 'revenue' }),
      );
      const topRes = await handlers.getTopProducts(
        req({ timeRange: '30d', limit: '100' }),
      );

      const metricBody = metricRes.body as AnalyticsResponse<MetricDetail>;
      const topBody = topRes.body as AnalyticsResponse<TopProduct[]>;

      const topProductsRevenue = topBody.data.reduce((s, p) => s + p.totalRevenue, 0);
      expect(topProductsRevenue).toBe(metricBody.data.summary.currentValue);
    });
  });

  // =========================================================================
  // All time-range presets work end-to-end
  // =========================================================================

  describe('All time-range presets', () => {
    const ranges = ['24h', '7d', '30d', '90d'] as const;

    for (const range of ranges) {
      it(`dashboard works with ${range}`, async () => {
        seedData();
        const res = await handlers.getDashboard(req({ timeRange: range }));
        expect(res.status).toBe(200);
        const body = res.body as AnalyticsResponse<DashboardData>;
        expect(body.success).toBe(true);
        expect(body.data.summaries).toHaveLength(4);
      });

      it(`metric detail works with ${range}`, async () => {
        seedData();
        const res = await handlers.getMetricDetail(
          req({ timeRange: range }, { type: 'revenue' }),
        );
        expect(res.status).toBe(200);
      });

      it(`top products works with ${range}`, async () => {
        seedData();
        const res = await handlers.getTopProducts(req({ timeRange: range }));
        expect(res.status).toBe(200);
      });
    }
  });
});

